import React, { useState, useEffect } from 'react';
import {
  Box,
  Typography,
  Paper,
  Button,
  Card,
  CardContent,
  TextField,
  Alert,
  List,
  ListItem,
  ListItemText,
  Chip,
  Grid,
  Avatar,
  Badge
} from '@mui/material';
import { Groups, VideoCall, PersonAdd, Share, Chat } from '@mui/icons-material';
import { useVoiceControl } from '../context/VoiceControlContext';

const API_BASE = 'http://localhost:8000';

const CollaborationPage = () => {
  const { speakFeedback } = useVoiceControl();
  const [sessionId, setSessionId] = useState('');
  const [participants, setParticipants] = useState([]);
  const [isConnected, setIsConnected] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [activeSessions, setActiveSessions] = useState([]);

  useEffect(() => {
    speakFeedback('Collaboration page loaded. You can say "create session", "join session", or "list sessions".');
    fetchActiveSessions();
    
    // Listen for voice page actions
    const handleVoiceAction = (event) => {
      const { action } = event.detail;
      switch (action) {
        case 'create':
        case 'create session':
          createSession();
          break;
        case 'join':
        case 'join session':
          joinSession();
          break;
        case 'leave':
        case 'leave session':
          leaveSession();
          break;
        case 'share':
        case 'share code':
          shareCode();
          break;
        case 'help':
          showHelp();
          break;
        default:
          break;
      }
    };

    window.addEventListener('voicePageAction', handleVoiceAction);
    return () => window.removeEventListener('voicePageAction', handleVoiceAction);
  }, []);

  const fetchActiveSessions = async () => {
    try {
      const response = await fetch(`${API_BASE}/collaboration/sessions/`);
      const data = await response.json();
      setActiveSessions(data.sessions || []);
    } catch (err) {
      console.error('Failed to fetch sessions:', err);
    }
  };

  const createSession = async () => {
    setLoading(true);
    try {
      const response = await fetch(`${API_BASE}/collaboration/create-session/`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: new URLSearchParams({
          session_name: 'Voice Coding Session',
          creator_name: 'User'
        })
      });
      const data = await response.json();
      setSessionId(data.session_id);
      setSuccess(`Session created: ${data.session_id}`);
      speakFeedback(`Session created with ID ${data.session_id}. Share this ID with collaborators.`);
      fetchActiveSessions();
    } catch (err) {
      setError('Failed to create session');
      speakFeedback('Failed to create session. Please try again.');
    }
    setLoading(false);
  };

  const joinSession = async () => {
    if (!sessionId.trim()) {
      setError('Please enter a session ID');
      speakFeedback('Please enter a session ID first');
      return;
    }
    
    setLoading(true);
    try {
      const response = await fetch(`${API_BASE}/collaboration/join-session/`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: new URLSearchParams({
          session_id: sessionId,
          participant_name: 'User'
        })
      });
      
      if (response.ok) {
        setIsConnected(true);
        setSuccess('Joined session successfully!');
        speakFeedback(`Successfully joined session ${sessionId}. You can now collaborate in real-time.`);
        // Here you would establish WebSocket connection
        connectWebSocket(sessionId);
      }
    } catch (err) {
      setError('Failed to join session');
      speakFeedback('Failed to join session. Please check the session ID.');
    }
    setLoading(false);
  };

  const leaveSession = () => {
    setIsConnected(false);
    setSessionId('');
    setParticipants([]);
    setSuccess('Left session');
    speakFeedback('Left collaboration session');
  };

  const shareCode = () => {
    if (!isConnected) {
      setError('Please join a session first');
      speakFeedback('Please join a session first before sharing code');
      return;
    }
    
    // Implement code sharing logic
    speakFeedback('Code shared with all participants');
  };

  const connectWebSocket = (sessionId) => {
    // WebSocket connection would be implemented here
    // For demonstration, we'll simulate participants
    setParticipants([
      { name: 'User', status: 'active', id: '1' },
      { name: 'Collaborator 1', status: 'active', id: '2' }
    ]);
  };

  const showHelp = () => {
    const helpText = `Collaboration voice commands:
    Say "Create session" to start a new collaboration session
    Say "Join session" to join an existing session
    Say "Leave session" to exit current session
    Say "Share code" to share your code with participants`;
    speakFeedback(helpText);
  };

  return (
    <Box sx={{ p: 3, maxWidth: 1200, mx: 'auto' }}>
      <Typography variant="h4" gutterBottom sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
        <Groups color="primary" />
        Real-Time Collaboration
      </Typography>
      
      <Typography variant="body1" sx={{ mb: 3, color: 'text.secondary' }}>
        🎤 Voice Commands: "Create session", "Join session", "Leave session", "Share code"
      </Typography>

      {error && (
        <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError('')}>
          {error}
        </Alert>
      )}

      {success && (
        <Alert severity="success" sx={{ mb: 2 }} onClose={() => setSuccess('')}>
          {success}
        </Alert>
      )}

      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              <VideoCall sx={{ mr: 1, verticalAlign: 'middle' }} />
              Session Management
            </Typography>

            <TextField
              fullWidth
              label="Session ID"
              value={sessionId}
              onChange={(e) => setSessionId(e.target.value)}
              sx={{ mb: 2 }}
              placeholder="Enter session ID to join or leave empty to create new"
            />

            <Box sx={{ display: 'flex', gap: 1, mb: 2, flexWrap: 'wrap' }}>
              <Button
                variant="contained"
                onClick={createSession}
                disabled={loading}
                startIcon={<PersonAdd />}
              >
                Create Session
              </Button>
              <Button
                variant="outlined"
                onClick={joinSession}
                disabled={!sessionId || loading}
                startIcon={<Groups />}
              >
                Join Session
              </Button>
              {isConnected && (
                <Button
                  variant="text"
                  onClick={leaveSession}
                  color="error"
                >
                  Leave Session
                </Button>
              )}
            </Box>

            {isConnected && (
              <Alert severity="success" sx={{ mb: 2 }}>
                <strong>Connected to session: {sessionId}</strong>
                <br />
                Real-time collaboration is active
              </Alert>
            )}

            <Box sx={{ display: 'flex', gap: 1, flexWrap: 'wrap' }}>
              <Chip label="🎤 Create session" variant="outlined" />
              <Chip label="🎤 Join session" variant="outlined" />
              <Chip label="🎤 Share code" variant="outlined" />
            </Box>
          </Paper>
        </Grid>

        <Grid item xs={12} md={6}>
          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              <Chat sx={{ mr: 1, verticalAlign: 'middle' }} />
              Participants ({participants.length})
            </Typography>

            {participants.length > 0 ? (
              <List>
                {participants.map((participant) => (
                  <ListItem key={participant.id}>
                    <Badge
                      color={participant.status === 'active' ? 'success' : 'default'}
                      variant="dot"
                      sx={{ mr: 2 }}
                    >
                      <Avatar sx={{ width: 32, height: 32 }}>
                        {participant.name[0]}
                      </Avatar>
                    </Badge>
                    <ListItemText 
                      primary={participant.name}
                      secondary={participant.status}
                    />
                  </ListItem>
                ))}
              </List>
            ) : (
              <Typography variant="body2" color="text.secondary">
                No participants yet. Create or join a session to start collaborating.
              </Typography>
            )}

            {isConnected && (
              <Box sx={{ mt: 2 }}>
                <Button
                  variant="outlined"
                  onClick={shareCode}
                  startIcon={<Share />}
                  fullWidth
                >
                  Share Current Code
                </Button>
              </Box>
            )}
          </Paper>
        </Grid>

        <Grid item xs={12}>
          <Paper sx={{ p: 3 }}>
            <Typography variant="h6" gutterBottom>
              Active Sessions
            </Typography>
            
            {activeSessions.length > 0 ? (
              <Grid container spacing={2}>
                {activeSessions.map((session) => (
                  <Grid item xs={12} sm={6} md={4} key={session.id}>
                    <Card>
                      <CardContent>
                        <Typography variant="h6">{session.name}</Typography>
                        <Typography variant="body2" color="text.secondary">
                          ID: {session.id}
                        </Typography>
                        <Typography variant="body2">
                          Participants: {session.participant_count}
                        </Typography>
                        <Button
                          size="small"
                          onClick={() => {
                            setSessionId(session.id);
                            speakFeedback(`Session ID ${session.id} entered`);
                          }}
                          sx={{ mt: 1 }}
                        >
                          Use This ID
                        </Button>
                      </CardContent>
                    </Card>
                  </Grid>
                ))}
              </Grid>
            ) : (
              <Typography variant="body2" color="text.secondary">
                No active sessions found.
              </Typography>
            )}
          </Paper>
        </Grid>
      </Grid>
    </Box>
  );
};

export default CollaborationPage;
